import"../chunks/DsnmJJEf.js";import"../chunks/CyPCCCDv.js";import{n as i,o,q as n}from"../chunks/B8uje50n.js";var a=o('<h1 id="cubes">Cubes</h1> <p>Cubes are the fundamental building blocks of custom models in Animated Java. They work exactly the same as standard Blockbench cubes, and produce custom item model JSON when exported.</p> <h2 id="entity-creation">Entity Creation</h2> <p>Cubes do <strong>not</strong> create their own entities when exported. Instead, they are baked into the item model JSON of their parent <a href="/docs/nodes/groups">Group</a>. The parent Group’s <code>minecraft:item_display</code> entity renders the cube geometry.</p> <h2 id="supported-features">Supported Features</h2> <ul><li><h4 id="tint-index">Tint Index</h4> <p>Cubes support Minecraft’s tint index feature for coloring faces based on biome color maps (e.g. grass, foliage, water tints). Set in the cube’s face properties.</p></li> <li><h4 id="light-emission">Light Emission</h4> <p>Allows the cube to emit a constant brightness level regardless of the ambient lighting in the world. Useful for glowing elements like eyes or screens.</p></li> <li><h4 id="rescale">Rescale</h4> <p>Allows bone entities to be rendered slightly larger than their nominal size by enabling the vanilla <code>rescale</code> flag in the model JSON.</p></li></ul> <h2 id="rotation-limitations">Rotation Limitations</h2> <p>Cube rotations in Animated Java follow the same rules as vanilla Minecraft item models:</p> <h3 id="for-minecraft-1204---1215">For Minecraft 1.20.4 - 1.21.5:</h3> <ul><li>Cubes can only be rotated on <strong>one axis at a time</strong>.</li> <li>Rotation values are limited to <strong>22.5-degree increments</strong> (0°, 22.5°, 45°, -22.5°, -45°).</li></ul> <h3 id="for-minecraft-1216---12110">For Minecraft 1.21.6 - 1.21.10:</h3> <ul><li>Cubes can only be rotated on <strong>one axis at a time</strong>.</li></ul> <h3 id="for-minecraft-12111-and-above">For Minecraft 1.21.11 and above:</h3> <ul><li>There are no rotation limitations for cubes in Minecraft 1.21.11 and above — cubes can be rotated freely on all axes with no restrictions.</li></ul> <p>Animated Java will automatically enforce these limitations based on the target Minecraft version selected in your Blueprint settings.</p> <aside class="admonition admonition-tip"><p class="admonition-title">Tip</p><div class="admonition-content"><p>If you need a cube at an arbitrary rotation on a version that doesn’t support it, place it inside a <a href="/docs/nodes/groups">Group</a> and rotate the Group instead. Groups (bones) have no rotation restrictions.</p></div></aside> <h2 id="size-limitations">Size Limitations</h2> <p>Unlike vanilla Minecraft item models, Animated Java <strong>removes all size limits</strong> — cubes can be any size.</p>',1);function d(e){var t=a();n(34),i(e,t)}export{d as component};
